class PortfolioBuilder {
    private Stack<PortfolioGroup> stack = new Stack<>();
    private PortfolioGroup root;

    public PortfolioBuilder(String rootName) {
        root = new PortfolioGroup(rootName);
        stack.push(root);
    }

    public PortfolioBuilder startSubPortfolio(String name) {
        PortfolioGroup sub = new PortfolioGroup(name);
        stack.peek().add(sub);
        stack.push(sub);   // dive deeper
        return this;
    }

    public PortfolioBuilder addStock(String symbol, double price) {
        stack.peek().add(new Stock(symbol, price));
        return this;
    }

    public PortfolioBuilder endSubPortfolio() {
        if (stack.size() > 1) stack.pop();   // return to parent
        return this;
    }

    public PortfolioGroup build() { return root; }
}

// CLIENT — reads like an outline
PortfolioGroup portfolio = new PortfolioBuilder("Main Account")
    .addStock("CASH", 5000)
    .startSubPortfolio("Tech Growth Fund")
        .addStock("AAPL", 1500)
        .addStock("NVDA", 2000)
        .startSubPortfolio("Crypto")
            .addStock("BTC", 50000)
        .endSubPortfolio()
    .endSubPortfolio()
    .addStock("Gold ETF", 3000)
    .build();
